-/// Type caster for holder types like std::shared_ptr, etc.
-template <typename type, typename holder_type> class type_caster_holder : public type_caster_base<type> {
-public:
-    using base = type_caster_base<type>;
-    using base::base;
-    using base::cast;
-    using base::typeinfo;
-    using base::value;
-    using base::temp;
