-        void multiply_vector_by_matrix(GLfloat vec[], GLfloat mat[], GLfloat* result)
-        {
-            const auto N = 4;
-            for (int i = 0; i < N; i++)
-            {
-                result[i] = 0;
-                for (int j = 0; j < N; j++)
-                {
-                    result[i] += vec[j] * mat[N*j + i];
-                }
-            }
-            return;
-        }
