-inline unsigned int string_to_hex(std::string str)
-{
-    std::string delimiter = "x";
-
-    auto pos = str.find(delimiter);
-    str.erase(0, pos + delimiter.length());
-
-    std::stringstream ss;
-    unsigned int value;
-    ss << str;
-    ss >> std::hex >> value;
-
-    return value;
-}
