-        throw std::logic_error("Invalid XML file - expecting Commands node to be present");
-
-    for (auto NodeI = node->first_node(); NodeI; NodeI = NodeI->next_sibling())
-    {
-        if (!strcmp(NodeI->name(), "Command"))
