+		nh.getParam("confidence", m_confidence);		
+		nh.getParam("estimate_center", m_estimateCenter);		
+		nh.getParam("max_number_of_objects", m_maxNumberOfObjects);
+		nh.getParam("use_CPU",m_use_CPU);
