+	void CRecognition::init(ros::NodeHandle& nh,const std::vector<std::string> & argv)
+	{
+
+		m_or_data = nullptr;
+		m_or_configuration = nullptr;	  		
+		m_no_subscribers = true;		
+		m_show_rgb = false;		
+		m_nh = nh;	
+
+		for(int i=0; i < argv.size(); i++)
+		{
+			if(argv[i] == "show_rgb")
+			{
+				m_show_rgb = true;
+			}
+		}
+	
+		image_transport::ImageTransport it(nh);
+				
+		m_sub_depthCameraInfo = nh.subscribe("camera/depth/camera_info", 1, &CRecognition::depthCameraImfoCallback, this);
+		m_recognized_objects_pub = nh.advertise<realsense_msgs::ObjectArray>("realsense/recognized_objects", 1);
+		
+
+		
+		if(m_show_rgb)
+		{
+			cv::namedWindow("viewColor");
+		}
